class Solution:
    def backspaceCompare(self, s, t):
        def nxt(x, i):
            skip = 0
            while i >= 0:
                if x[i] == '#':
                    skip += 1
                    i -= 1
                elif skip > 0:
                    skip -= 1
                    i -= 1
                else:
                    break
            return i
        i, j = len(s) - 1, len(t) - 1
        while i >= 0 or j >= 0:
            i = nxt(s, i)
            j = nxt(t, j)
            if i >= 0 and j >= 0:
                if s[i] != t[j]:
                    return False
            elif i >= 0 or j >= 0:
                return False
            i -= 1
            j -= 1
        return True

