var backspaceCompare = function(s, t) {
    const nxt = (x, i) => {
        let skip = 0;
        while (i >= 0) {
            if (x[i] === '#') { skip++; i--; }
            else if (skip > 0) { skip--; i--; }
            else break;
        }
        return i;
    };
    let i = s.length - 1, j = t.length - 1;
    while (i >= 0 || j >= 0) {
        i = nxt(s, i);
        j = nxt(t, j);
        if (i >= 0 && j >= 0) {
            if (s[i] !== t[j]) return false;
        } else if (i >= 0 || j >= 0) {
            return false;
        }
        i--; j--;
    }
    return true;
};
